import React, { useState, useCallback, useMemo } from 'react';
import { Button, Select, MoneyInput, NumberInput, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { ktService } from '../../../services/kt/ktService';
import type { OpeningInventoryDto, MaterialDto, WarehouseDto } from '../../../services/kt/models';
import { yearOptions } from '../../../constants/voucher';
import { openingBalancePageLabels } from '../../../constants/openingBalancePageLabels';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
import erp from '../../../styles/erpPage.module.css';

import { formatVnd } from '../../../utils/formatters';

const TEST_ID = 'erp-so-du-vat-tu';
const labels = openingBalancePageLabels.soDuVatTu;

const SoDuVatTuPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const [year, setYear] = useState(String(new Date().getFullYear()));
  const [items, setItems] = useState<OpeningInventoryDto[]>([]);
  const [materials, setMaterials] = useState<MaterialDto[]>([]);
  const [warehouses, setWarehouses] = useState<WarehouseDto[]>([]);
  const [warehouseFilter, setWarehouseFilter] = useState('');
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);

  const load = useCallback(() => {
    setLoading(true);
    Promise.all([
      ktService.getOpeningInventory(Number(year)),
      ktService.searchMaterials({ page: 1, pageSize: 500 }),
      ktService.getWarehouses({ page: 1, pageSize: 500, isActive: true }),
    ])
      .then(([inventory, materialRes, warehouseRes]) => {
        setItems(inventory);
        setMaterials(materialRes.items);
        setWarehouses(warehouseRes.items);
      })
      .catch(err => dispatch(addToast({ message: getApiErrorMessage(err, labels.loadError), type: 'error' })))
      .finally(() => setLoading(false));
  }, [year, dispatch]);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => { if (!cancelled) load(); }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [load]);

  const updateItem = (idx: number, patch: Partial<OpeningInventoryDto>) => {
    setItems(prev => prev.map((it, i) => {
      if (i !== idx) return it;
      const quantity = patch.quantity ?? it.quantity;
      const unitPrice = patch.unitPrice ?? it.unitPrice;
      return { ...it, ...patch, quantity, unitPrice, amount: quantity * unitPrice };
    }));
  };

  const deleteRow = (idx: number) => {
    setItems(prev => prev.filter((_, i) => i !== idx));
  };

  const addRow = () => {
    const defaultWarehouse = warehouses[0];
    setItems(prev => ([
      ...prev,
      {
        materialCode: '',
        materialName: '',
        warehouseId: defaultWarehouse?.id ?? '',
        warehouseName: defaultWarehouse?.name ?? '',
        unitCode: '',
        quantity: 0,
        unitPrice: 0,
        amount: 0,
      },
    ]));
  };

  const materialOptions = useMemo(
    () => materials.map(m => ({ value: m.code, label: `${m.code} — ${m.name}` })),
    [materials],
  );
  const warehouseOptions = useMemo(
    () => warehouses.map(w => ({ value: w.id, label: `${w.code} — ${w.name}` })),
    [warehouses],
  );
  const warehouseFilterOptions = useMemo(
    () => [{ value: '', label: labels.warehouseFilterAll }, ...warehouseOptions],
    [warehouseOptions],
  );

  const displayedRows = useMemo(
    () => (warehouseFilter ? items.filter(it => it.warehouseId === warehouseFilter) : items),
    [items, warehouseFilter],
  );

  const handleSave = async () => {
    setSaving(true);
    try {
      const normalizedItems = items
        .filter(it => it.materialCode && it.warehouseId)
        .map(it => ({ ...it, amount: it.quantity * it.unitPrice }));
      await ktService.saveOpeningInventory({ year: Number(year), items: normalizedItems });
      dispatch(addToast({ message: labels.saveSuccess, type: 'success' }));
      load();
    } catch (e: unknown) {
      dispatch(addToast({ message: getApiErrorMessage(e, labels.saveError), type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className={erp.page} data-testid={TEST_ID}>
      <div className={erp.pageHeader}>
        <div className={erp.titleBlock}>
          <h1 className={erp.title}><i className="fas fa-boxes" /> {labels.title}</h1>
        </div>
      </div>
      <div className={erp.filtersBar} data-testid={`${TEST_ID}-filters`}>
        <Select
          value={year}
          onChange={e => setYear(e.target.value)}
          options={yearOptions()}
          data-testid={`${TEST_ID}-year`}
        />
        <Select
          value={warehouseFilter}
          onChange={e => setWarehouseFilter(e.target.value)}
          options={warehouseFilterOptions}
          data-testid={`${TEST_ID}-warehouse-filter`}
        />
        <Button variant="secondary" onClick={addRow} data-testid={`${TEST_ID}-add-row`}>
          {labels.addRow}
        </Button>
        <Button variant="primary" onClick={handleSave} loading={saving} data-testid={`${TEST_ID}-save`}>{labels.save}</Button>
        <ListSearchRefreshButtons testIdPrefix={TEST_ID} onSearch={load} onRefresh={load} showSearch={false} />
      </div>
      <div className={erp.tableCard} data-testid={`${TEST_ID}-table`}>
        {loading ? <div className={erp.loading}>{labels.loading}</div> : displayedRows.length === 0 ? (
          <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>{labels.empty(year)}</div>
        ) : (
          <div className={erp.tableWrapper}>
            <table className={erp.table}>
              <thead>
                <tr>
                  <th>{labels.colMaterialCode}</th>
                  <th>{labels.colMaterialName}</th>
                  <th>{labels.colWarehouse}</th>
                  <th className={erp.colRight}>{labels.colQty}</th>
                  <th className={erp.colRight}>{labels.colUnitPrice}</th>
                  <th className={erp.colRight}>{labels.colAmount}</th>
                  <th>{labels.colActions}</th>
                </tr>
              </thead>
              <tbody>{displayedRows.map((it, idx) => {
                const rowKey = `${it.materialCode || 'new'}-${it.warehouseId || idx}-${idx}`;
                const sourceIndex = items.indexOf(it);
                return (
                <tr key={rowKey} data-testid={`${TEST_ID}-row-${idx + 1}`}>
                  <td>
                    <Select
                      value={it.materialCode}
                      onChange={e => {
                        const material = materials.find(m => m.code === e.target.value);
                        updateItem(sourceIndex, {
                          materialCode: e.target.value,
                          materialName: material?.name ?? '',
                          unitCode: material?.unitCode ?? '',
                        });
                      }}
                      options={materialOptions}
                      placeholder={labels.colMaterialSelectPlaceholder}
                      data-testid={`${TEST_ID}-row-${idx + 1}-material`}
                    />
                  </td>
                  <td>{it.materialName ?? '—'}</td>
                  <td>
                    <Select
                      value={it.warehouseId}
                      onChange={e => {
                        const warehouse = warehouses.find(w => w.id === e.target.value);
                        updateItem(sourceIndex, {
                          warehouseId: e.target.value,
                          warehouseName: warehouse?.name ?? '',
                        });
                      }}
                      options={warehouseOptions}
                      placeholder={labels.colWarehouseSelectPlaceholder}
                      data-testid={`${TEST_ID}-row-${idx + 1}-warehouse`}
                    />
                  </td>
                  <td>
                    <NumberInput
                      value={it.quantity}
                      onChange={val => updateItem(sourceIndex, { quantity: Number(val) || 0 })}
                      data-testid={`${TEST_ID}-row-${idx + 1}-qty`}
                    />
                  </td>
                  <td>
                    <MoneyInput
                      value={it.unitPrice}
                      onChange={val => updateItem(sourceIndex, { unitPrice: Number(val) || 0 })}
                      data-testid={`${TEST_ID}-row-${idx + 1}-price`}
                    />
                  </td>
                  <td className={erp.colRight}>{formatVnd(it.amount)}</td>
                  <td>
                    <Button
                      variant="danger"
                      onClick={() => deleteRow(sourceIndex)}
                      data-testid={`${TEST_ID}-row-${idx + 1}-delete`}
                    >
                      {labels.deleteRow}
                    </Button>
                  </td>
                </tr>
              );})}</tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default SoDuVatTuPage;
